import{_ as a,o as t,c as i,a2 as r}from"./chunks/framework.N6Nd-M9-.js";const b=JSON.parse('{"title":"📊 平均法","description":"","frontmatter":{},"headers":[],"relativePath":"notes/企业文化/组长手册/08-平均法.md","filePath":"notes/企业文化/组长手册/08-平均法.md"}'),c={name:"notes/企业文化/组长手册/08-平均法.md"};function n(o,e,s,l,h,d){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="📊-平均法" tabindex="-1">📊 平均法 <a class="header-anchor" href="#📊-平均法" aria-label="Permalink to &quot;📊 平均法&quot;">​</a></h1><blockquote><p>平均法这一核心概念是根植在同创主悦的每一个发展阶段、每一个部门及每一个运作领域中的成功定律，因此学习这一核心概念及如何正确运用是非常重要的。平均法是教学中的机率概念，问的人越多，机会就越大。在销售部门，平均法意味着用兴奋、积极的态度去拜访150至200位以上的客户。争取到最少50至70位以上的客户听完五步，就会得到一个区间的成交率—大约是1/5到1/10的成交机率。平均法是公司系统多年来用实际的市场营销验证出来的定律，是具有可靠性及科学性的。</p></blockquote><div class="tc-card tc-card-blue"><p class="tc-title tc-blue">💡 核心要点</p><p class="tc-body">平均法是销售中的成功定律，通过大量拜访客户、保持积极态度，实现稳定的成交率。</p></div><hr><h2 id="📈-一、要更有效的实现平均法-需要格外注意以下几个方面" tabindex="-1">📈 一、要更有效的实现平均法，需要格外注意以下几个方面： <a class="header-anchor" href="#📈-一、要更有效的实现平均法-需要格外注意以下几个方面" aria-label="Permalink to &quot;📈 一、要更有效的实现平均法，需要格外注意以下几个方面：&quot;">​</a></h2><hr><h3 id="_01-做足八小时-——-充分利用时间" tabindex="-1">01 做足八小时 —— 充分利用时间 <a class="header-anchor" href="#_01-做足八小时-——-充分利用时间" aria-label="Permalink to &quot;01 做足八小时 —— 充分利用时间&quot;">​</a></h3><div class="tc-container tc-container-blue"><p class="tc-body" style="font-size:14px;line-height:1.8;"> 每天要先做好充分的地区准备，合理的安排及运用地区并规划好运作时间，以期让你每天拜访客户的时间都能获得效益最大化。 </p></div><hr><h3 id="_02-保持地区-——-不挑选地区" tabindex="-1">02 保持地区 —— 不挑选地区 <a class="header-anchor" href="#_02-保持地区-——-不挑选地区" aria-label="Permalink to &quot;02 保持地区 —— 不挑选地区&quot;">​</a></h3><div class="tc-container tc-container-green"><p class="tc-body" style="font-size:14px;line-height:1.8;"> 不论是什么地区，都要用积极乐观的态度去面对一见门就进。充分把握地区中的每一个角落、最大化地增加见人的密度，有助于更快熟悉市场、统筹安排、节约时间、减少盲目性。如此，最能了解自己地区的人和他们所想要的，在同等的地区经营的时间可以更久。 </p></div><hr><h3 id="_03-不挑选客户" tabindex="-1">03 不挑选客户 <a class="header-anchor" href="#_03-不挑选客户" aria-label="Permalink to &quot;03 不挑选客户&quot;">​</a></h3><div class="tc-container tc-container-orange"><p class="tc-body" style="font-size:14px;line-height:1.8;"> 相信任何人都是潜在顾客，不论是什么人，都用热情兴奋的态度去面对，见人就打招呼。充分挖掘市场和顾客潜力的同时，展现个人的能力和风范。 </p></div><hr><h3 id="_04-有质量的沟通-——-兴奋度和良好的态度" tabindex="-1">04 有质量的沟通 —— 兴奋度和良好的态度 <a class="header-anchor" href="#_04-有质量的沟通-——-兴奋度和良好的态度" aria-label="Permalink to &quot;04 有质量的沟通 —— 兴奋度和良好的态度&quot;">​</a></h3><div class="tc-container tc-container-red"><p class="tc-body" style="font-size:14px;line-height:1.8;"> 兴奋的五步才能感染客户，良好的沟通才能有助成交。所以在业务中要保持好轻松、积极、乐观、兴奋的态度与足够多的客户做良好的沟通，才能得到平均法的效益。 </p></div><hr><h3 id="_05-hustle-——-节奏快且有效率" tabindex="-1">05 HUSTLE —— 节奏快且有效率 <a class="header-anchor" href="#_05-hustle-——-节奏快且有效率" aria-label="Permalink to &quot;05 HUSTLE —— 节奏快且有效率&quot;">​</a></h3><div class="tc-container tc-container-blue"><p class="tc-body" style="font-size:14px;line-height:1.8;"> 外出作业中，走路的速度要快，成交要快，不可磨客户。 </p></div><hr><h3 id="_06-见足够多的客户" tabindex="-1">06 见足够多的客户 <a class="header-anchor" href="#_06-见足够多的客户" aria-label="Permalink to &quot;06 见足够多的客户&quot;">​</a></h3><div class="tc-container tc-container-green"><p class="tc-body" style="font-size:14px;line-height:1.8;"> 做销售最大的问题就是客户少，抱怨多。没有结果什么都是无济于事的，倒不如建设性检讨过自己。人数的量变，带来销售的质变。你拜访的客户越多，你成交的客户就越多。当然咱们指的拜访都是用心的拜访，认真去对待的拜访。记住，在外出作业的时候，不让他人浪费自己的时间，少聊天，多见顾客。 </p></div><hr><h2 id="🎯-二、相信平均法" tabindex="-1">🎯 二、相信平均法 <a class="header-anchor" href="#🎯-二、相信平均法" aria-label="Permalink to &quot;🎯 二、相信平均法&quot;">​</a></h2><div class="tc-container tc-container-orange"><p class="tc-body" style="font-size:14px;line-height:1.8;"> 平均法实现的三种状况——早上、下午、平均分布在一整天。只有真正相信平均法的人才能验证平均法的果效，特别是在成交量不理想时，还可以保持更积极、更兴奋的态度去问下一位客户，因为他知道，每一个“不”代表着更接近下一个“要”，机会和希望永远都在下一位客户，前面的“不”并不会让他放弃及失去态度，只有继续保持良好积极的心态，平均法才会带给你下一个“要”。平均法很清楚地告诉我们，要提高业绩，最好的方法就是问足够多的人数，同时必须始终保持一个轻松积极的心态与客户做良好的沟通，那么平均法就会得到更好的实现。任何人，若想要在销售业务方面成功，就一定要充分了解和全面运用平均法，而平均法在我们建立团队和管理公司方面也同样需要使用并发挥其效益。正确的掌握并有效的运用平均法这一核心概念，将会为你的业务和管理打下坚实的基础，取得更大的发展。 </p></div><hr><h2 id="📝-总结" tabindex="-1">📝 总结 <a class="header-anchor" href="#📝-总结" aria-label="Permalink to &quot;📝 总结&quot;">​</a></h2><div class="tc-highlight"><p class="tc-title tc-center" style="color:#fff;line-height:2;letter-spacing:1px;"> 平均法是当你快失去信心时，能为你注入的强心剂<br> 平均法是当你快失去态度时，能让你重新调整态度再出发<br> 平均法是当你失望和悲伤时，能让你点燃希望和惊喜<br> 平均法是你保持良好态度的回报 </p></div><hr><div class="tc-container tc-container-blue" style="margin-top:20px;"><p class="tc-body tc-center" style="font-size:14px;line-height:1.8;"><strong>失败的人，什么都不做；一般的人，只做这一点；<br> 成功的人，多做一点点；顶尖的人，再多做一点！</strong></p></div>',31)])])}const _=a(c,[["render",n]]);export{b as __pageData,_ as default};
